//BIDC전자세금계산서 발행 확인 및 수정 팝업
scwin.f_Confirm = async function () {
    if (ds_out.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, Array("데이타"));
        return;
    }

    var i = 0;
    var count = 0;

    // 조회결과 데이터셋의 루프만큼
    for (i = 0; i < ds_out.getTotalRow(); i++) {
        // 체크된 것만 로직을 타고, 
        if (ds_out.getCellData(i, "chk") == 1) {
            count = count + 1;
        }
    }
    if (count > 1) {
        await $c.gus.cfAlertMsg("세금계산서 발행 확인은 1건씩 가능합니다.");
        return false;
    }

    var slipNo;
    var spplyAmt;
    var vat;
    var sumAmt;
    var remark;
    var vatNo;

    // 조회결과 데이터셋의 루프만큼
    for (i = 0; i < ds_out.getTotalRow(); i++) {
        // 체크된 것만 로직을 타고, 
        if (ds_out.getCellData(i, "chk") == 1) {
            slipNo = ds_out.getCellData(i, "slipNo");
            spplyAmt = ds_out.getCellData(i, "spplyAmt");
            vat = ds_out.getCellData(i, "vat");
            sumAmt = ds_out.getCellData(i, "sumAmt");
            remark = ds_out.getCellData(i, "remark");
            vatNo = ds_out.getCellData(i, "vatNo");
        }
    }

    let data = {
        slipNo: slipNo,
        spplyAmt: spplyAmt,
        vat: vat,
        sumAmt: sumAmt,
        remark: remark,
        vatNo: vatNo
    };

    let win_url = "/ui/ac/fi/electaxinvc/fi_900_01_09p.xml";

    let opts = {
        id: "smpPop"
        , popupName: "전자세금계산서 발행 확인"
        , modal: true
        , type: "browserPopup"
        , width: 1030
        , height: 580
        , title: "전자세금계산서 발행 확인"
    };

    var rt = await $c.win.openPopup(win_url, opts, data);

}


